class SamlResponseProcessor {

    public SamlAuthentication processBase64PostResponse(String base64SamlResponse) {
        String xml = new String(Base64.getDecoder().decode(base64SamlResponse), StandardCharsets.UTF_8);
        return processResponseXml(xml);
    }

    public SamlAuthentication processBase64RedirectResponse(String base64DeflatedSamlResponse) {
        byte[] compressed = Base64.getDecoder().decode(base64DeflatedSamlResponse);
        try (InflaterInputStream in = new InflaterInputStream(new ByteArrayInputStream(compressed), new Inflater(true))) {
            byte[] buf = in.readAllBytes();
            String xml = new String(buf, StandardCharsets.UTF_8);
            return processResponseXml(xml);
        } catch (Exception e) {
            throw new SamlProcessingException("Failed to inflate Redirect SAMLResponse", e);
        }
    }

    public SamlAuthentication processResponseXml(String xml) {
        Document doc = parseXmlSecurely(xml);

        XPathFactory xPathFactory = XPathFactory.newInstance();
        XPath xp = xPathFactory.newXPath();
        xp.setNamespaceContext(new SamlNs());

        String responseId = eval(xp, doc, "/samlp:Response/@ID");
        String issueInstant = eval(xp, doc, "/samlp:Response/@IssueInstant");
        String issuer = evalAny(xp, doc, "/samlp:Response/saml:Issuer/text()");
        if (issuer == null || issuer.isBlank()) issuer = evalAny(xp, doc, "//saml:Assertion/saml:Issuer/text()");

        String statusCode = eval(xp, doc, "/samlp:Response/samlp:Status/samlp:StatusCode/@Value");
        if (statusCode == null || statusCode.isBlank()) throw new SamlProcessingException("Missing StatusCode");
        if (!statusCode.endsWith(":Success")) throw new SamlProcessingException("Non-success StatusCode: " + statusCode);

        Node assertion = node(xp, doc, "(//saml:Assertion)[1]");
        if (assertion == null) throw new SamlProcessingException("Missing Assertion");

        String assertionId = evalOn(xp, assertion, "./@ID");
        String nameId = evalAnyOn(xp, assertion, ".//saml:Subject/saml:NameID/text()");
        if (nameId == null || nameId.isBlank()) nameId = evalAny(xp, doc, "//saml:Subject/saml:NameID/text()");
        if (nameId == null || nameId.isBlank()) throw new SamlProcessingException("Missing NameID");

        String sessionIndex = evalAnyOn(xp, assertion, ".//saml:AuthnStatement/@SessionIndex");

        String notBefore = evalAnyOn(xp, assertion, ".//saml:Conditions/@NotBefore");
        String notOnOrAfter = evalAnyOn(xp, assertion, ".//saml:Conditions/@NotOnOrAfter");

        validateTimeWindow(notBefore, notOnOrAfter, 180);

        Map<String, List<String>> attributes = extractAttributes(xp, assertion);

        return new SamlAuthentication(
                issuer,
                nameId,
                sessionIndex,
                issueInstant,
                notBefore,
                notOnOrAfter,
                attributes,
                assertionId,
                responseId
        );
    }

    private static Map<String, List<String>> extractAttributes(XPath xp, Node assertion) {
        Map<String, List<String>> map = new LinkedHashMap<>();
        NodeList attrs = nodes(xp, assertion, ".//saml:AttributeStatement/saml:Attribute");
        for (int i = 0; i < attrs.getLength(); i++) {
            Element attr = (Element) attrs.item(i);
            String name = attr.getAttribute("Name");
            if (name == null || name.isBlank()) continue;

            NodeList values = attr.getElementsByTagNameNS("urn:oasis:names:tc:SAML:2.0:assertion", "AttributeValue");
            List<String> out = new ArrayList<>();
            for (int j = 0; j < values.getLength(); j++) {
                Node v = values.item(j);
                String text = v.getTextContent();
                if (text != null) {
                    text = text.trim();
                    if (!text.isEmpty()) out.add(text);
                }
            }
            if (!out.isEmpty()) map.put(name, out);
        }
        return map;
    }

    private static void validateTimeWindow(String notBefore, String notOnOrAfter, long clockSkewSeconds) {
        Instant now = Instant.now();
        if (notBefore != null && !notBefore.isBlank()) {
            Instant nb = parseSamlInstant(notBefore);
            if (now.plusSeconds(clockSkewSeconds).isBefore(nb)) {
                throw new SamlProcessingException("Assertion not yet valid (NotBefore=" + notBefore + ")");
            }
        }
        if (notOnOrAfter != null && !notOnOrAfter.isBlank()) {
            Instant noa = parseSamlInstant(notOnOrAfter);
            if (now.minusSeconds(clockSkewSeconds).isAfter(noa) || now.equals(noa)) {
                throw new SamlProcessingException("Assertion expired (NotOnOrAfter=" + notOnOrAfter + ")");
            }
        }
    }

    private static Instant parseSamlInstant(String s) {
        try {
            return Instant.parse(s);
        } catch (Exception e) {
            throw new SamlProcessingException("Invalid SAML time: " + s, e);
        }
    }

    private static Document parseXmlSecurely(String xml) {
        try {
            DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
            dbf.setNamespaceAware(true);
            dbf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
            dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
            dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            dbf.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            dbf.setXIncludeAware(false);
            dbf.setExpandEntityReferences(false);
            dbf.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            dbf.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

            DocumentBuilder db = dbf.newDocumentBuilder();
            return db.parse(new ByteArrayInputStream(xml.getBytes(StandardCharsets.UTF_8)));
        } catch (Exception e) {
            throw new SamlProcessingException("Failed to parse SAMLResponse XML", e);
        }
    }

    private static String eval(XPath xp, Object item, String expr) {
        try {
            return xp.evaluate(expr, item);
        } catch (Exception e) {
            throw new SamlProcessingException("XPath failed: " + expr, e);
        }
    }

    private static String evalAny(XPath xp, Object item, String expr) {
        String v = eval(xp, item, expr);
        return (v == null || v.isBlank()) ? null : v;
    }

    private static String evalOn(XPath xp, Node item, String expr) {
        try {
            return xp.evaluate(expr, item);
        } catch (Exception e) {
            throw new SamlProcessingException("XPath failed: " + expr, e);
        }
    }

    private static String evalAnyOn(XPath xp, Node item, String expr) {
        String v = evalOn(xp, item, expr);
        return (v == null || v.isBlank()) ? null : v;
    }

    private static Node node(XPath xp, Object item, String expr) {
        try {
            return (Node) xp.evaluate(expr, item, XPathConstants.NODE);
        } catch (Exception e) {
            throw new SamlProcessingException("XPath node failed: " + expr, e);
        }
    }

    private static NodeList nodes(XPath xp, Object item, String expr) {
        try {
            return (NodeList) xp.evaluate(expr, item, XPathConstants.NODESET);
        } catch (Exception e) {
            throw new SamlProcessingException("XPath nodes failed: " + expr, e);
        }
    }
}

class SamlNs implements NamespaceContext {
    private static final Map<String, String> MAP = Map.of(
            "samlp", "urn:oasis:names:tc:SAML:2.0:protocol",
            "saml", "urn:oasis:names:tc:SAML:2.0:assertion",
            "ds", "http://www.w3.org/2000/09/xmldsig#"
    );

    @Override
    public String getNamespaceURI(String prefix) {
        if (prefix == null) return XMLConstants.NULL_NS_URI;
        return MAP.getOrDefault(prefix, XMLConstants.NULL_NS_URI);
    }

    @Override
    public String getPrefix(String namespaceURI) {
        for (Map.Entry<String, String> e : MAP.entrySet()) {
            if (Objects.equals(e.getValue(), namespaceURI)) return e.getKey();
        }
        return null;
    }

    @Override
    public Iterator<String> getPrefixes(String namespaceURI) {
        List<String> out = new ArrayList<>();
        for (Map.Entry<String, String> e : MAP.entrySet()) {
            if (Objects.equals(e.getValue(), namespaceURI)) out.add(e.getKey());
        }
        return out.iterator();
    }
}

final class SessionUtils {
    private SessionUtils() {}

    public static Optional<SamlSession> currentSamlSession(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session == null) return Optional.empty();
        Object o = session.getAttribute(SamlSession.SESSION_KEY);
        if (o instanceof SamlSession s) return Optional.of(s);
        return Optional.empty();
    }

    public static String attributeFirst(SamlSession s, String name) {
        if (s == null || name == null) return null;
        List<String> v = s.getAttributes().get(name);
        if (v == null || v.isEmpty()) return null;
        return v.get(0);
    }

    public static String stableUserKey(SamlSession s) {
        if (s == null) return null;
        String src = (s.getIssuer() == null ? "" : s.getIssuer()) + "|" + (s.getNameId() == null ? "" : s.getNameId());
        return sha256Hex(src);
    }

    private static String sha256Hex(String in) {
        try {
            MessageDigest md = MessageDigest.getInstance("SHA-256");
            byte[] dig = md.digest(in.getBytes(StandardCharsets.UTF_8));
            StringBuilder sb = new StringBuilder(dig.length * 2);
            for (byte b : dig) sb.append(Character.forDigit((b >>> 4) & 0xF, 16)).append(Character.forDigit(b & 0xF, 16));
            return sb.toString();
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}